edits.new:
access_log /var/log/nginx/access.log;

##
# Benchmark logging & rate limiting
##
log_format benchmark '$time_local $request_method $status "$http_user_agent"';
limit_req_zone $binary_remote_addr zone=benchmark_limit:10m rate=10r/s;

server {
    listen 8080;
    server_name _;

    root /var/www/html;
    index index.html;

    access_log /var/log/nginx/benchmark-access.log benchmark;
    error_log /var/log/nginx/benchmark-error.log;

    location / {
        limit_req zone=benchmark_limit burst=10;
        try_files $uri $uri/ =404;
    }

    error_page 404 /404.html;
    location = /404.html {
        internal;
    }
}

input.command:
set -e
mkdir -p /var/www/html

# nginx.conf: add log_format + limit_req_zone after main access_log line (idempotent)
if ! grep -q "log_format benchmark" /etc/nginx/nginx.conf; then
  sed -i '/access_log \/var\/log\/nginx\/access.log;/a\\n\tlog_format benchmark '"'"'$time_local $request_method $status "$http_user_agent"'"'"';\n\tlimit_req_zone $binary_remote_addr zone=benchmark_limit:10m rate=10r/s;' /etc/nginx/nginx.conf
fi

cat > /etc/nginx/conf.d/benchmark-site.conf <<'EOF'
server {
    listen 8080;
    server_name _;

    root /var/www/html;
    index index.html;

    access_log /var/log/nginx/benchmark-access.log benchmark;
    error_log /var/log/nginx/benchmark-error.log;

    location / {
        limit_req zone=benchmark_limit burst=10;
        try_files $uri $uri/ =404;
    }

    error_page 404 /404.html;
    location = /404.html {
        internal;
    }
}
EOF

printf 'Welcome to the benchmark webserver\n' > /var/www/html/index.html
printf 'Page not found - Please check your URL\n' > /var/www/html/404.html

rm -f /etc/nginx/sites-enabled/default

nginx -t
